function createDeviceCosts(box_ref, op_return, op_cost, paid, set_date,number) {
    var logs = new GlideRecord("u_ev_device_costs");
    logs.initialize();
	logs.u_number = number;
    logs.u_ev_box = box_ref;
    logs.u_operational_return = op_return;
    logs.u_operational_cost = op_cost;
    logs.u_paid = paid;
    logs.sys_created_on = set_date;
    logs.insert();
}

var number = 'COST0001013'
var box_ref = '214cd727832b52108eb710c5eeaad3db';
var paid = 20.2;
var op_return = 21.2;
var op_cost = op_return - 5.5;
var set_date = '2025-02-12 13:19:43';

createDeviceCosts(box_ref,op_return,op_cost,paid,set_date,number);
